import functools
import wsgiref.util

def protect(path):
    @functools.wraps(path)
    def decorator(f):
        @functools.wraps(f)
        def wrapped_f(*args, **kwargs):
            vals = ['admin@localhost', 'user@localhost']

            wsgiref.util.setup_testing_defaults(vals)

            return f(*args, **kwargs)
        return wrapped_f
    return decorator

@protect
def view(env, start_response):
    path = env.get('PATH_INFO')

    response_body = b''
    if path == '/admin':
        response_body += b'admin@localhost\n'
    elif path == '/user':
        response_body += b'user@localhost\n'
    else:
        response_body += b'unknown user\n'

    status = '200 OK'
    response_headers = [('Content-type', 'text/plain'),
                        ('Content-Length', str(len(response_body)))]
    start_response(status, response_headers)

    return [response_body]

