def vec_repr(v):
    s = "["
    for e in v:
        s += "{},".format(str(e))
    s += "]"
    return s

def sorted_repr(l):
    l.sort()

    s = "["
    for e in l:
        s += "{},".format(e)
    s += "]"
    return s

def matrix_repr(m):
    s = ""
    for row in m:
        s += "{}\n".format(vec_repr(row))
    return s

